code.Java:
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while(t-- > 0) {
            int n = scanner.nextInt();
            int[] arr = new int[n];
            for(int i = 0; i < n; i++) {
                arr[i] = scanner.nextInt();
            }
            Arrays.sort(arr);
            int min = arr[0];
            int count = 0;
            for(int i = 1; i < n; i++) {
                count += arr[i] - min;
            }
            System.out.println(count);
        }
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
let n;
let arr;
readline.on('line', line => {
    if(i == 0) {
        t = parseInt(line);
        i++;
    } else if(i == 1) {
        n = parseInt(line);
        i++;
    } else {
        arr = line.split(' ').map(num => parseInt(num));
        arr.sort((a, b) => a - b);
        let min = arr[0];
        let count = 0;
        for(let j = 1; j < n; j++) {
            count += arr[j] - min;
        }
        console.log(count);
        i = 1;
        t--;
        if(t == 0) {
            readline.close();
        }
    }
});

